kIncomplete:"Unmark",nextLesson:"Next lesson",prevLesson:"Previous lesson",minutesShort:"min",freePreview:"Free preview",freePreviewLbl:"Free preview",backToProgram:"Back to product",backToPrograms:"Back to programs",allLessonsComplete:"Congratulations! You completed all lessons.",adminPrograms:"Programs",subscriptionsTab:"Subscriptions",priceCentsHint:"Price in cents (9900 = 99 BGN)",stripePriceHint:"from Stripe Dashboard → Products",addProgram:"New product",editProgram:"Edit product",addModule:"New module",editModule:"Edit module",addLesson:"New lesson",editLesson:"Edit lesson",videoUrl:"Video URL",videoUrlHint:"YouTube, Vimeo or Bunny Stream URL",durationMin:"Duration (min)",coverUrl:"Cover URL",selectProgram:"Select product",selectModule:"Select module",programModules:"Modules",programLessons:"Lessons",noModules:"No modules",noLessons:"No lessons",allLabel:"All",statusDraft:"Draft",buyProgram:"Buy product",buyProgramFor:"Buy for",purchaseSuccess:"Purchase successful! Welcome.",purchaseError:"Purchase error. Please try again.",lockedLesson:"This lesson is locked. Purchase the product to access it.",includedStudio:"Included in studio membership",purchased:"Purchased",currencyBGN:"BGN",programLocked:"Locked product",programLockedDesc:"This is a paid product. Purchase it for full access.",uploadVideoBtn:"Upload",uploadingVideo:"Uploading video...",tabMyPrograms:"My Programs",tabResources:"Resources",tabSynrgMethod:"SYNRG Method",resourcesTitle:"Resources",resourcesOverline:"Bonus content",noResources:"No resources available",watchResource:"Watch",resourcesLocked:"Available after purchasing a program",adminResources:"Resources",addResource:"New resource",editResource:"Edit resource",categoryLbl:"Category",privacyPolicyTitle:"Privacy Policy",consentPre:"I have read and accept the",privacyPolicyLink:"Privacy Policy",errConsentRequired:"You must accept the privacy policy",deleteMyAccount:"Delete my account",deleteAccountTitle:"Delete account",deleteAccountConfirm:"Are you sure? All your data (food diary, workouts, weight, steps) will be permanently deleted.",deleteAccountBtn:"Yes, delete everything",upgradeOnlineBanner:"SYNRG ONLINE",upgradeOnlineDesc:"Programs · Bookings · Coach · SYNRG method",upgradeSeeBtn:"View →",lockedPrograms:"Online programs",lockedProgramsDesc:"Training & nutrition plans",lockedStudio:"Studio training",lockedStudioDesc:"Personal training sessions",tour_welcome_eyebrow:"WELCOME TO THE SYNRG METHOD",tour_welcome_title:"Hi there!",tour_welcome_body:"You are starting an 8-week journey. Small daily steps to reach the results you want without forcing yourself. Let us give you a quick tour of the app.",tour_navDashboard_eyebrow:"SECTION · TODAY",tour_navDashboard_title:"Your day",tour_navDashboard_body:"This is where you start every day — you can see your weekly goals, daily tasks and workouts. Let us show you what is inside.",tour_focus_eyebrow:"TODAY · FOCUS THIS WEEK",tour_focus_title:"Weekly goals",tour_focus_body:"These are the things that will build your habits so you stay in shape — without constantly starting new diets or restrictive regimens.",tour_dailies_eyebrow:"TODAY · DAILY TASKS",tour_dailies_title:"Daily habits",tour_dailies_body:"This is where you log the three daily habits — weight, food and steps. Small entries every day become big change over 8 weeks.",tour_workout_eyebrow:"TODAY · WORKOUTS",tour_workout_title:"Movement for the week",tour_workout_body:"The workouts for the week with exact exercises, rounds and time. Open a workout to see the execution step by step.",tour_chat_eyebrow:"TODAY · COACH",tour_chat_title:"Got a question? Write!",tour_chat_body:"Your mentor is one click away. Whenever you are stuck, have a doubt or just want to fine-tune the plan — write any time.",tour_navProgress_eyebrow:"SECTION · PROGRESS",tour_navProgress_title:"Unlock badges for consistency, earn points and compete with the others",tour_navProgress_body:"This is where you follow your progress over time — consistency badges and ranking within the community.",tour_badges_eyebrow:"PROGRESS · BADGES",tour_badges_title:"Your progress",tour_badges_body:"You collect badges for every streak — weight logged, food, steps, workouts. They visualize your progress week by week.",tour_ranking_eyebrow:"PROGRESS · RANKING",tour_ranking_title:"You are not alone",tour_ranking_body:"See how other clients in the community are doing. A bit of friendly competition for extra motivation.",tour_navResources_eyebrow:"SECTION · RESOURCES",tour_navResources_title:"Help for everyday life",tour_navResources_body:"Recipes and useful resources — always on hand whenever you need ideas or guidance.",tour_recipes_eyebrow:"RESOURCES · RECIPES",tour_recipes_title:"Inspiration for your menu",tour_recipes_body:"Pre-defined meals with portion sizes, macros and steps. Pick easily from here whenever you need a meal idea.",tour_skip:"Skip",tour_back:"Back",tour_next:"Next →",tour_start:"Start",tour_close:"Close",todayLabel:"TODAY",weekLabel:"Week",weekEmpty:"This week has no content yet.",daysShort:"days",logWeight:"Log weight",logFood:"Log your food",logSteps:"Log your steps",weightInfoTitle:"Why weigh yourself every day",weightInfoBody:"Body weight fluctuates day to day from water retention, cycle phase, salt intake, and stress. A single number tells you nothing — the trend tells you everything. Weigh yourself every morning under the same conditions (before breakfast, after the bathroom, naked) and watch the 4-5 day average. That's how you see the real direction without panicking over daily noise.",foodInfoBody:`Calorie counting works... but not forever — nobody does it for life. The point of 1-2 weeks of logging isn't a "diet" — it's knowledge: where most of your calories come from, how much you actually eat, what 150 g of meat, one portion of rice, or a handful of nuts looks like. That knowledge becomes the foundation of intuition — and good decisions stop requiring you to count every bite.`,foodInfoTitle:"Why log your food",stepsInfoTitle:"Why count steps",stepsInfoBody:`You don't need to jump from 5,000 to 15,000 steps — that's force, and it won't last. Start with 2,000–3,000 more than you do now. That's roughly 90,000 extra steps a month — about 1 kg of fat burned per month, without extra training. Gradual increase, sustainable habit. That's the difference between a "diet" and real life.`,taskNoExtra:"No additional explanation for this task.",whyThisWorks:"Why this works",sourceLabel:"Source",eduDisclaimer:"Educational content only — not a substitute for medical consultation.",markUndone:"Mark as not done",markDone:"Done for today",closeBtn:"Close",workoutLoading:"Loading workout...",workoutToday:"Today's workout",workoutComingSoon:"Coming soon",workoutComingSoonBody:"We're organizing the exercise library. Check back soon.",workoutTitle:"Workout",workoutStart:"Start",workoutStartNow:"Start now",workoutRound:"ROUND",workoutSideLeft:" · LEFT SIDE",workoutSideRight:" · RIGHT SIDE",workoutBetweenRounds:"REST BETWEEN ROUNDS",workoutBreathe:"Breathe · next round coming",workoutNext:"Next:",workoutDay:"DAY",workoutOfTotal:"of",workoutSummary:(e,n,r,s,a)=>`${e} rounds × ${n} exercises · ${r} min total · ${s} sec switch / ${a} sec rest between rounds`,workoutSec:"sec",workoutPerSide:" / side",workoutDone:"Done.",workoutDoneBody:"One round stronger than yesterday. Easy breathing, some water, a bit of stretching.",workoutRestart:"Restart",workoutToDashboard:"To dashboard",workoutTypeWarmup:"WARMUP",workoutTypeCooldown:"COOLDOWN",workoutTypeMobility:"MOBILITY",workoutTypeMain:"MAIN",workoutFinish:"Finish",workoutDoneBanner:"Workout · Done",workoutReplay:"Replay",yourMentor:"Your mentor",heroEyebrow:(e,n)=>`SYNRG METHOD · DAY ${e} OF ${n}`,weekOfTotal:(e,n)=>`Week ${e} of ${n}`,coachQTitle:"Got a question?",coachQSub:"Message your mentor →",coachQBtn:"Chat",expertTitle:"THE TEAM BEHIND THE METHOD",expertIntro:"Every recommendation comes from doctors and coaches who work with you."